		/* checkOutboundStart */
		SELECT
            COUNT(1)
        FROM
            ${apiCommon.schema}.WTAKIT WT
        INNER JOIN ${apiCommon.schema}.OOUBIT OOU
            ON OOU.OUTBOKY = WT.OUTBOKY
            AND OOU.OUTBOIT = WT.OUTBOIT
        WHERE
            OOU.OUTBOKY = #{param.outboky}
            AND WT.TASKOKY = #{param.taskoky}

            	AND WT.TASKSTS = #{param.tasksts}

